  ('optometrist-moex-01556', 'optometrist', 'optometrist-moex-109-b0a2f330', 'sub-optometrist-02', NULL, 'single_choice', '依驗光人員法第46條規定，若有違反收費標準，超額或擅立項目收費，應處：', '["新臺幣一萬元以上五萬元以下罰鍰，並令其限期改善。屆期未改善，處三個月以上一年以下停業處 分或廢止其開業執照", "新臺幣二萬元以上十萬元以下罰鍰，並令其限期改善。屆期未改善，處一個月以上一年以下停業處 分或廢止其開業執照", "新臺幣三萬元以上十五萬元以下罰鍰，並令其限期改善。屆期未改善，處一個月以上半年以下停業 處分或廢止其開業執照", "新臺幣三萬元以上十五萬元以下罰鍰，並令其限期改善。屆期未改善，處三個月以上一年以下停業 處分或廢止其開業執照"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:48+00:00", "source_pdf_sha1": "bbde246e8075", "answer_pdf_sha1": "9c4914153e8c", "source_family": "moex-gov-tw", "moex": {"exam_code": "109180", "c": "401", "s": "1501", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "眼球解剖生理學與倫理法規", "year": "109", "exam_name": "109年專技人員高等考試建築師、32類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)暨普通考試不動產經紀人、記帳士考...", "original_question_number": 39, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-01557', 'optometrist', 'optometrist-moex-109-b0a2f330', 'sub-optometrist-02', NULL, 'single_choice', '依驗光人員法施行細則第7條，下列何者屬於驗光人員可以驗光配鏡的一般隱形眼鏡？', '["治療近視用的角膜塑型鏡片", "圓錐角膜的治療鏡片", "成年人的近視、遠視鏡片", "角膜或眼內術後的矯正鏡片"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:48+00:00", "source_pdf_sha1": "bbde246e8075", "answer_pdf_sha1": "9c4914153e8c", "source_family": "moex-gov-tw", "moex": {"exam_code": "109180", "c": "401", "s": "1501", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "眼球解剖生理學與倫理法規", "year": "109", "exam_name": "109年專技人員高等考試建築師、32類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)暨普通考試不動產經紀人、記帳士考...", "original_question_number": 40, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-01558', 'optometrist', 'optometrist-moex-109-b0a2f330', 'sub-optometrist-02', NULL, 'single_choice', '有關醫事人員團體申請認可辦理繼續教育課程與積分審查之認定及採認，下列敘述何者錯誤？', '["須設立滿3年，且為全國性之醫事人員學會、各該類醫事人員相關學會或公會", "中央主管機關受理申請辦理繼續教育課程與積分之審查，得至該醫事人員團體實地訪查", "應向主管機關提出報告，並接受主管機關對其人員、設備、衛生、安全、收費情形、作業等之檢查", "應檢具申請函及各項所須文件、資料之計畫書，向中央主管機關提出，經核定後，始得為之"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:48+00:00", "source_pdf_sha1": "bbde246e8075", "answer_pdf_sha1": "9c4914153e8c", "source_family": "moex-gov-tw", "moex": {"exam_code": "109180", "c": "401", "s": "1501", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "眼球解剖生理學與倫理法規", "year": "109", "exam_name": "109年專技人員高等考試建築師、32類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)暨普通考試不動產經紀人、記帳士考...", "original_question_number": 41, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-01559', 'optometrist', 'optometrist-moex-109-b0a2f330', 'sub-optometrist-02', NULL, 'single_choice', '有關驗光人員考試之規定，下列敘述何者正確？①驗光人員法公布施行前曾在醫療機構或眼鏡行從事 驗光業務滿3年，並具專科以上學校畢業資格，經中央主管機關審查合格者，得應驗光師高等考試及', '["驗光師考試及格人員，由考選部報請考試院發給考試及格證書，並函內政部查照", "應 考人曾有褫奪公權尚未復權情事者，依法不得應本考試", "應考人有冒名頂替情事者，依法不得應本 考試  ⑤應考人以詐術或其他不正當方法，使考試發生不正確之結果者，依法將受到取消應考資格、 扣考、不予錄取或撤銷其考試及格資格等處分  ⑥應考人有偽造或變造應考證件情事者，依法須滿5 年以上，方得再應本考試", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:48+00:00", "source_pdf_sha1": "bbde246e8075", "answer_pdf_sha1": "9c4914153e8c", "source_family": "moex-gov-tw", "moex": {"exam_code": "109180", "c": "401", "s": "1501", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "眼球解剖生理學與倫理法規", "year": "109", "exam_name": "109年專技人員高等考試建築師、32類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)暨普通考試不動產經紀人、記帳士考...", "original_question_number": 42, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-01560', 'optometrist', 'optometrist-moex-109-b0a2f330', 'sub-optometrist-02', NULL, 'single_choice', '依據驗光人員執業處所的眼鏡公司（商號）法令，下列敘述何者錯誤？', '["眼鏡公司（商號）內設立驗光所者，該驗光所不得與眼鏡公司（商號）共用招牌", "須是登記為眼鏡批發、零售業", "須於機構內設立驗光所", "驗光人員法公布施行起10年期滿，眼鏡公司未有驗光人員，停止驗光業務"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:48+00:00", "source_pdf_sha1": "bbde246e8075", "answer_pdf_sha1": "9c4914153e8c", "source_family": "moex-gov-tw", "moex": {"exam_code": "109180", "c": "401", "s": "1501", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "眼球解剖生理學與倫理法規", "year": "109", "exam_name": "109年專技人員高等考試建築師、32類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)暨普通考試不動產經紀人、記帳士考...", "original_question_number": 43, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-01561', 'optometrist', 'optometrist-moex-109-b0a2f330', 'sub-optometrist-02', NULL, 'single_choice', '負責驗光人員因故不能執行業務時，有關代理的敘述，下列何者正確？', '["代理者限定資深驗光師", "代理期間，最長不得超過45日", "代理的驗光師其條件限制，須在依法所定之機構執行業務2年以上", "代理期間超過45日者，應由被代理者報請中央主管機關備查"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:48+00:00", "source_pdf_sha1": "bbde246e8075", "answer_pdf_sha1": "9c4914153e8c", "source_family": "moex-gov-tw", "moex": {"exam_code": "109180", "c": "401", "s": "1501", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "眼球解剖生理學與倫理法規", "year": "109", "exam_name": "109年專技人員高等考試建築師、32類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)暨普通考試不動產經紀人、記帳士考...", "original_question_number": 44, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-01562', 'optometrist', 'optometrist-moex-109-b0a2f330', 'sub-optometrist-02', NULL, 'single_choice', '有關驗光所業務倫理之規定，下列敘述何者正確？①收取費用應開給收費明細表及收據，違反者處新', '["不得違反收費標準，超額或擅立項目收費，違反者處新臺幣二萬 元以上十萬元以下罰鍰", "應將其開業執照及收費標準揭示於明顯處，違反者處新臺幣一萬元以上五 萬元以下罰鍰，並令其限期改善；屆期未改善者，處一個月以上一年以下停業處分", "應以其申請人 為負責驗光人員，對該機構業務負督導責任，違反者處新臺幣三萬元以上十五萬元以下罰鍰  ⑤執行 業務之紀錄及醫師開具之照會單或醫囑單，應妥為保管，並至少保存三年，違反者處新臺幣二萬元以 上十萬元以下罰鍰", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:48+00:00", "source_pdf_sha1": "bbde246e8075", "answer_pdf_sha1": "9c4914153e8c", "source_family": "moex-gov-tw", "moex": {"exam_code": "109180", "c": "401", "s": "1501", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "眼球解剖生理學與倫理法規", "year": "109", "exam_name": "109年專技人員高等考試建築師、32類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)暨普通考試不動產經紀人、記帳士考...", "original_question_number": 45, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-01563', 'optometrist', 'optometrist-moex-109-b0a2f330', 'sub-optometrist-02', NULL, 'single_choice', '下列何者不屬於驗光人員法中所稱的低視力者輔助器具？①特製加稜鏡眼鏡  ②手持式放大鏡  ③', '["桌上型擴視機  ⑤攜帶式望遠鏡  ⑥輔助照明燈", "", "", "⑥"]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:48+00:00", "source_pdf_sha1": "bbde246e8075", "answer_pdf_sha1": "9c4914153e8c", "source_family": "moex-gov-tw", "moex": {"exam_code": "109180", "c": "401", "s": "1501", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "眼球解剖生理學與倫理法規", "year": "109", "exam_name": "109年專技人員高等考試建築師、32類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)暨普通考試不動產經紀人、記帳士考...", "original_question_number": 46, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL)
